   133	static void trigger_regular_bsr(NR_UE_MAC_INST_t *mac, NR_LogicalChannelIdentity_t lcid, bool sr_DelayTimerApplied)
   134	{
   135	  // Regular BSR trigger
   136	  mac->scheduling_info.BSR_reporting_active |= NR_BSR_TRIGGER_REGULAR;
   137	  mac->scheduling_info.regularBSR_trigger_lcid = lcid;
   138	  LOG_D(NR_MAC, "Triggering regular BSR for LCID %ld\n", lcid);
   139	  // if the BSR is triggered for a logical channel for which logicalChannelSR-DelayTimerApplied with value true
   140	  // start or restart the logicalChannelSR-DelayTimer
   141	  // else stop the logicalChannelSR-DelayTimer
   142	  if (sr_DelayTimerApplied)
   143	    nr_timer_start(&mac->scheduling_info.sr_DelayTimer);
   144	  else
   145	    nr_timer_stop(&mac->scheduling_info.sr_DelayTimer);
