   148	void update_mac_timers(NR_UE_MAC_INST_t *mac)
   149	{
   150	  nr_timer_tick(&mac->ra.contention_resolution_timer);
   151	  for (int j = 0; j < NR_MAX_SR_ID; j++)
   152	    nr_timer_tick(&mac->scheduling_info.sr_info[j].prohibitTimer);
   153	  nr_timer_tick(&mac->scheduling_info.sr_DelayTimer);
   154	  bool retxBSR_expired = nr_timer_tick(&mac->scheduling_info.retxBSR_Timer);
   155	  if (retxBSR_expired) {
   156	    LOG_D(NR_MAC, "retxBSR timer expired\n");
   157	    for (int i = 0; i < mac->lc_ordered_list.count; i++) {
   158	      nr_lcordered_info_t *lc_info = mac->lc_ordered_list.array[i];
   159	      NR_LogicalChannelIdentity_t lcid = lc_info->lcid;
