   161	      NR_LC_SCHEDULING_INFO *lc_sched_info = get_scheduling_info_from_lcid(mac, lcid);
   162	      if (lc_sched_info->LCGID != NR_INVALID_LCGID && lc_sched_info->LCID_buffer_remain > 0) {
   163	        LOG_D(NR_MAC, "Triggering regular BSR after retxBSR timer expired\n");
   164	        trigger_regular_bsr(mac, lcid, lc_info->sr_DelayTimerApplied);
   165	        break;
   166	      }
   167	    }
   168	  }
   169	  bool periodicBSR_expired = nr_timer_tick(&mac->scheduling_info.periodicBSR_Timer);
   170	  if (periodicBSR_expired) {
   171	    // periodicBSR-Timer expires, trigger BSR
   172	    mac->scheduling_info.BSR_reporting_active |= NR_BSR_TRIGGER_PERIODIC;
   173	    LOG_D(NR_MAC, "[UE %d] MAC BSR Triggered PeriodicBSR Timer expiry\n", mac->ue_id);
